queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?rolename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasRoles ?child ; p:hasEditorial_Teams ?parent . } GROUP BY ?child }
  ?child p:RoleName ?rolename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Editorial_Teams } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?rolename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasRoles ?child ; p:hasEditorial_Teams ?parent . } GROUP BY ?child }
  ?child p:RoleName ?rolename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Editorial_Teams } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?teamname ?rolename WHERE {
  ?editorial_teams_roles a :Editorial_Teams_Roles .
  ?roles a :Roles .
  ?editorial_teams_roles p:hasRoles ?roles .
  ?editorial_teams a :Editorial_Teams .
  ?editorial_teams_roles p:hasEditorial_Teams ?editorial_teams .
  ?editorial_teams p:TeamName ?teamname .
  ?roles p:RoleName ?rolename .
} }
}
